class Solution:
  def calculate_min_column_width(self, layout):
    max_item_width = 0
    for item in layout.items:
      max_item_width = max(max_item_width, item.width)
    min_column_width = max_item_width
    max_grid_width = 0
    for item in layout.items:
      max_grid_width = max(max_grid_width, item.width)
    return max(min_column_width, max_grid_width)
